JS_CODE = 'var Qs = [\n  { text:"ペットの種類は？", opts:["犬（小型・5kg未満）","犬（中・大型・5kg以上）","猫","その他（小動物・鳥等）"], key:"type" },\n  { text:"年齢は？", opts:["子犬・子猫（1歳未満）","成犬・成猫（1〜7歳）","シニア（8歳以上）"], key:"age" },\n  { text:"現在の体型・体重は？", opts:["やせぎみ","ちょうど良い","少し太りぎみ","かなり肥満"], key:"weight" },\n  { text:"気になる健康上の悩みは？", opts:["毛並み・皮膚が気になる","消化・お腹の調子","アレルギー・食物過敏","特になし・健康維持したい"], key:"concern" },\n  { text:"フードにかけられる月額予算は？", opts:["〜2,000円","2,000〜5,000円","5,000〜10,000円","10,000円以上（プレミアム）"], key:"budget" }\n];\n\nvar foodMap = {\n  allergy: { emoji:"🌿", type:"グレインフリー（穀物不使用）フード", desc:"アレルギーの原因になりやすい小麦・大豆を除いたフード。消化が良く皮膚・被毛の改善も期待できます。", tips:"• 同じタンパク源を続けず数種類をローテーション\\n• 切り替えは10日かけてゆっくり行う\\n• 便の状態・皮膚の様子を記録する" },\n  diet: { emoji:"🥦", type:"ダイエット・低カロリーフード", desc:"カロリーを抑えつつ必要な栄養素をバランスよく含んだフード。満腹感を高める食物繊維が豊富。", tips:"• 1日の給与量を守り、おやつは総摂取量の10%以内\\n• 食事を1日2〜3回に分けて与える\\n• 週1回体重を量って変化を記録する" },\n  senior: { emoji:"🦴", type:"シニア対応フード（低リン・関節ケア）", desc:"高齢ペットの腎臓・関節に配慮した低タンパク・低リンのフード。グルコサミン配合で関節をサポート。", tips:"• 腎臓病予防のため水分摂取を増やす（ウェットフード混合も可）\\n• 関節への負担を減らすため食事台を高くする\\n• 定期的な健康診断（年2回以上）を実施する" },\n  puppy: { emoji:"🌟", type:"パピー・キトン（成長期）フード", desc:"成長期に必要なカルシウム・DHA・タンパク質が豊富なフード。骨・脳・免疫の発達をサポート。", tips:"• 1日3〜4回の少量頻回食が理想\\n• 月齢に合わせたフードに切り替えを\\n• 肥満にならないよう給与量を守る" },\n  standard: { emoji:"🍗", type:"バランス重視のプレミアムフード", desc:"総合栄養食として必要な栄養素がバランスよく含まれたフード。添加物・着色料不使用のプレミアムタイプ。", tips:"• 年齢・体重に合わせた給与量を守る\\n• 常に新鮮な水を飲めるようにする\\n• フードの変更は徐々に行う（7〜10日かけて）" }\n};\n\nvar cur=0, ans={};\n\nfunction startDiagnosis() { show(\'questions\'); renderQ(); }\n\nfunction show(name) {\n  document.querySelectorAll(\'.screen\').forEach(function(s){ s.classList.remove(\'active\'); });\n  document.getElementById(\'screen-\'+name).classList.add(\'active\');\n}\n\nfunction renderQ() {\n  var q=Qs[cur];\n  var pct=Math.round((cur+1)/Qs.length*100);\n  document.getElementById(\'q-label\').textContent=\'質問 \'+(cur+1)+\' / \'+Qs.length;\n  document.getElementById(\'q-pct\').textContent=pct+\'%\';\n  document.getElementById(\'prog\').style.width=pct+\'%\';\n  document.getElementById(\'q-text\').textContent=q.text;\n  var c=document.getElementById(\'opts\'); c.innerHTML=\'\';\n  q.opts.forEach(function(opt,i){\n    var b=document.createElement(\'button\');\n    b.className=\'option-btn\'; b.textContent=opt;\n    b.onclick=function(){ pick(i,opt,q.key); };\n    c.appendChild(b);\n  });\n}\n\nfunction pick(i,val,key) {\n  ans[key]={i:i,val:val};\n  document.querySelectorAll(\'.option-btn\').forEach(function(b,j){ b.classList.toggle(\'selected\',j===i); });\n  setTimeout(function(){\n    cur++;\n    if(cur<Qs.length){ renderQ(); } else { show(\'loading\'); setTimeout(showResults,1600); }\n  },300);\n}\n\nfunction showResults() {\n  var concernIdx = ans.concern ? ans.concern.i : 3;\n  var ageIdx = ans.age ? ans.age.i : 1;\n  var weightIdx = ans.weight ? ans.weight.i : 1;\n\n  var key;\n  if(concernIdx===2) { key=\'allergy\'; }\n  else if(weightIdx>=2) { key=\'diet\'; }\n  else if(ageIdx===2) { key=\'senior\'; }\n  else if(ageIdx===0) { key=\'puppy\'; }\n  else { key=\'standard\'; }\n\n  var food=foodMap[key];\n  document.getElementById(\'res-emoji\').textContent=food.emoji;\n  document.getElementById(\'res-type\').textContent=food.type;\n  document.getElementById(\'res-desc\').textContent=food.desc;\n  document.getElementById(\'res-tips\').innerHTML=food.tips.replace(/\\n/g,\'<br>\');\n\n  var budgetIdx=ans.budget?ans.budget.i:1;\n  var petType=ans.type?ans.type.i:0;\n  var petEmoji=petType<=1?\'🐕\':\'🐈\';\n  var searchTerm=encodeURIComponent((petType<=1?\'犬\':\'猫\')+(budgetIdx>=2?\' プレミアム\':\'\')+(key===\'allergy\'?\' グレインフリー\':key===\'diet\'?\' ダイエット\':key===\'senior\'?\' シニア\':key===\'puppy\'?\' パピー\':\'\')+\' ドッグフード\');\n  var amazonUrl=\'https://www.amazon.co.jp/s?k=\'+searchTerm+\'&tag=appadaycrea0f-22\';\n\n  document.getElementById(\'aff-area\').innerHTML=\'<a href="\'+amazonUrl+\'" target="_blank" rel="noopener" class="block bg-yellow-400 text-gray-900 font-bold py-3 px-4 rounded-xl text-center text-sm hover:bg-yellow-500 transition">\'+petEmoji+\' Amazonで\'+food.type+\'を探す →</a><p class="text-xs text-gray-400 text-center mt-2">Amazonアソシエイトプログラム参加中</p>\';\n\n  show(\'results\');\n}\n\nfunction restart() { '
